// First page already fetched; paginate through remaining pages
let allRecords = $input.all();
let nextPageToken = allRecords[0]?.json?.nextPageToken;
let accessToken = $('获取钉钉Token').first().json.accessToken;
// Code 节点不解析 {{ $env.X }}，从上一个 HTTP 节点的 URL 中提取或用硬编码
// 这里从拉取钉钉记录节点的 URL 参数中获取 appToken 和 tableId
const fetchUrl = $('拉取钉钉记录').first().json;
// 从环境变量通过 process.env 获取（n8n Code 节点支持）
const appToken = process.env.DINGTALK_APP_TOKEN || '';
const tableId = process.env.DINGTALK_TABLE_ID || '';

while (nextPageToken) {
  const resp = await $http.request({
    method: 'GET',
    url: `https://api.dingtalk.com/v1.0/apaas/data/spreadsheets/${appToken}/records?tableId=${tableId}&pageSize=100&nextPageToken=${nextPageToken}`,
    headers: {
      'x-acs-dingtalk-access-token': accessToken
    },
    returnFullResponse: true
  });

  const body = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
  const newRecords = body?.result?.data || body?.data || [];
  nextPageToken = body?.result?.nextPageToken || body?.nextPageToken;

  for (const r of newRecords) {
    allRecords.push({ json: r });
  }
}

return allRecords;

// Build dingtalk_record_id -> metadata lookup
const metadataArr = $('获取sync_metadata').first().json;
const metaMap = {};
if (Array.isArray(metadataArr)) {
  for (const m of metadataArr) {
    metaMap[m.dingtalk_record_id] = m;
  }
}

const dingtalkRecords = $input.all();
const results = [];

for (const item of dingtalkRecords) {
  const rec = item.json;
  const recordId = rec.recordId || rec.id || '';
  const meta = metaMap[recordId];

  // Skip records synced FROM Supabase (prevent loop)
  if (rec.fields?.updater === '[DINGTALK_SYNC]') continue;

  let is_new = true;
  let skip = false;
  const robot_id = meta?.robot_id || null;

  if (meta?.robot_id) {
    is_new = false;
    const lastSynced = new Date(meta.last_synced_at || 0).getTime();
    const modified = new Date(rec.gmtModified || 0).getTime();
    if (modified <= lastSynced) {
      skip = true; // No changes since last sync
    }
  }

  // Map DingTalk fields -> Supabase columns
  const fields = rec.fields || {};
  const borrowedVal = (fields['是否借出'] || '').toString().trim().toUpperCase();

  const robot = {
    type: fields['机器人类型'] || null,
    serial: fields['出厂编号'] || null,
    status: fields['状态'] || null,
    person: fields['关联责任人'] || null,
    ip: fields['IP'] || null,
    location: fields['位置'] || null,
    notes: fields['备注'] || null,
    borrowed: borrowedVal === 'OK',
    borrowed_to: fields['借用人'] || null,
    updater: '[DINGTALK_SYNC]'
  };

  // Time fields -> ISO
  if (fields['借出时间']) {
    robot.borrowed_at = new Date(fields['借出时间']).toISOString();
  }
  if (fields['预计归还']) {
    robot.return_due = new Date(fields['预计归还']).toISOString();
  }

  results.push({
    json: {
      robot,
      dingtalk_record_id: recordId,
      robot_id,
      is_new,
      skip
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true } }];

const items = $input.all();
const newRecords = items.filter(i => i.json.is_new && !i.json.skip);
const results = [];

// Build a lookup from Supabase robots for new records
let existingMap = {};
if (newRecords.length > 0) {
  // Get all robots to check for duplicates
  try {
    const resp = await $http.request({
      method: 'GET',
      url: `{{ $env.SUPABASE_URL }}/rest/v1/robots?select=id,type,serial`,
      headers: {
        'apikey': '{{ $env.SUPABASE_SERVICE_KEY }}',
        'Authorization': 'Bearer {{ $env.SUPABASE_SERVICE_KEY }}'
      }
    });
    const robots = Array.isArray(resp) ? resp : (resp?.data || []);
    for (const r of robots) {
      const key = `${r.type}__${r.serial}`;
      existingMap[key] = r.id;
    }
  } catch (e) {
    // Continue without dedup if query fails
  }
}

for (const item of items) {
  const data = item.json;
  if (data.skip) {
    results.push(item);
    continue;
  }

  if (data.is_new) {
    const key = `${data.robot.type}__${data.robot.serial}`;
    const existingId = existingMap[key];
    if (existingId) {
      // Duplicate found: switch to PATCH
      data.is_new = false;
      data.robot_id = existingId;
      data._method = 'PATCH';
    } else {
      data._method = 'POST';
    }
  } else {
    data._method = 'PATCH';
  }

  results.push({ json: data });
}

return results;

// Supabase response overwrites original data, so get context from查重 node
const prevItems = $('新增记录查重').all();
const responses = $input.all();
const results = [];

for (let i = 0; i < responses.length; i++) {
  const resp = responses[i].json;
  const prev = prevItems[i]?.json || {};
  let robotId = prev.robot_id || null;

  // Supabase returns array with Prefer: return=representation
  if (!robotId && Array.isArray(resp) && resp.length > 0) {
    robotId = resp[0]?.id;
  } else if (!robotId && resp?.id) {
    robotId = resp.id;
  }

  results.push({
    json: {
      dingtalk_record_id: prev.dingtalk_record_id || '',
      robot_id: robotId
    }
  });
}

return results;
